// Generated by GitHub Copilot
import { useEffect, useMemo, useState } from "react";
import "./App.css";

const API_BASE_URL = import.meta.env.VITE_API_URL || "http://127.0.0.1:8000";

const SAMPLE_ROWS = [
    { brightness: 0.82, density: 0.21, motion_score: 0.61, label: 1, zone: "gate-a" },
    { brightness: 0.74, density: 0.17, motion_score: 0.52, label: 1, zone: "gate-a" },
    { brightness: 0.48, density: 0.11, motion_score: 0.23, label: 0, zone: "yard" },
    { brightness: 0.59, density: 0.19, motion_score: 0.44, label: 0, zone: "yard" },
    { brightness: 0.9, density: 0.29, motion_score: 0.78, label: 1, zone: "dock" },
];

const SAMPLE_CANDIDATES = [
    {
        candidate_id: "frame_0001",
        image_uri: "local://sample/frame_0001.jpg",
        predicted_label: "person",
        confidence: 0.88,
        bbox: [41, 31, 168, 229],
    },
    {
        candidate_id: "frame_0002",
        image_uri: "local://sample/frame_0002.jpg",
        predicted_label: "motorbike",
        confidence: 0.76,
        bbox: [71, 40, 242, 268],
    },
];

/**
 * Parse user-provided JSON text into an array payload with safe fallback.
 * @param {string} text - JSON text expected to represent an array.
 * @returns {Array} Parsed array.
 */
function parseArrayJson(text) {
    const parsed = JSON.parse(text);
    if (!Array.isArray(parsed)) {
        throw new Error("JSON must be an array payload.");
    }
    return parsed;
}

/**
 * Returns unreviewed candidates by comparing candidate ids with submitted corrections.
 * @param {object} task - Annotation task payload from backend.
 * @returns {Array} Pending candidates.
 */
function getPendingCandidates(task) {
    const corrected = new Set((task.corrections || []).map((item) => item.candidate_id));
    return (task.candidates || []).filter((candidate) => !corrected.has(candidate.candidate_id));
}

/**
 * Main UI for diagnostics, recommendation ranking, and annotation review loop.
 * @returns {JSX.Element} Application root element.
 */
function App() {
    const [datasetRowsText, setDatasetRowsText] = useState(JSON.stringify(SAMPLE_ROWS, null, 2));
    const [targetColumn, setTargetColumn] = useState("label");
    const [taskType, setTaskType] = useState("classification");
    const [diagnostics, setDiagnostics] = useState(null);
    const [recommendations, setRecommendations] = useState([]);

    const [datasetName, setDatasetName] = useState("surveillance-dataset-v1");
    const [annotationModelName, setAnnotationModelName] = useState("yolov5s");
    const [candidatesText, setCandidatesText] = useState(JSON.stringify(SAMPLE_CANDIDATES, null, 2));
    const [annotationTasks, setAnnotationTasks] = useState([]);

    const [busy, setBusy] = useState(false);
    const [error, setError] = useState("");
    const [success, setSuccess] = useState("");

    /**
     * Loads annotation tasks from backend for review queue visibility.
     * @returns {Promise<void>} Completion signal.
     */
    async function loadAnnotationTasks() {
        const response = await fetch(`${API_BASE_URL}/annotations/tasks?limit=20`);
        if (!response.ok) {
            throw new Error(`Failed to load annotation tasks (${response.status})`);
        }
        const payload = await response.json();
        setAnnotationTasks(payload.tasks || []);
    }

    useEffect(() => {
        let active = true;

        async function init() {
            try {
                if (!active) {
                    return;
                }
                await loadAnnotationTasks();
            } catch (requestError) {
                if (active) {
                    setError(
                        requestError instanceof Error
                            ? requestError.message
                            : "Failed to initialize annotation queue"
                    );
                }
            }
        }

        init();
        return () => {
            active = false;
        };
    }, []);

    const diagnosticsCards = useMemo(() => {
        if (!diagnostics) {
            return [];
        }
        return [
            { title: "Rows", value: diagnostics.row_count },
            { title: "Columns", value: diagnostics.column_count },
            { title: "Hints", value: diagnostics.task_hints?.length || 0 },
            {
                title: "Target Correlations",
                value: Object.keys(diagnostics.correlation_to_target || {}).length,
            },
        ];
    }, [diagnostics]);

    /**
     * Calls diagnostics endpoint and stores computed quality profile state.
     * @returns {Promise<void>} Completion signal.
     */
    async function handleRunDiagnostics() {
        setBusy(true);
        setError("");
        setSuccess("");
        try {
            const rows = parseArrayJson(datasetRowsText);
            const response = await fetch(`${API_BASE_URL}/diagnostics`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ rows, target_column: targetColumn || null }),
            });

            if (!response.ok) {
                throw new Error(`Diagnostics request failed (${response.status})`);
            }

            const payload = await response.json();
            setDiagnostics(payload);
            setSuccess("Diagnostics computed successfully.");
        } catch (requestError) {
            setError(requestError instanceof Error ? requestError.message : "Diagnostics request failed");
        } finally {
            setBusy(false);
        }
    }

    /**
     * Calls recommendation endpoint using diagnostics context and selected task type.
     * @returns {Promise<void>} Completion signal.
     */
    async function handleRecommendModels() {
        if (!diagnostics) {
            setError("Run diagnostics before requesting recommendations.");
            return;
        }

        setBusy(true);
        setError("");
        setSuccess("");
        try {
            const response = await fetch(`${API_BASE_URL}/recommendations`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    task_type: taskType,
                    diagnostics,
                    objective: "maximize annotation throughput with strong model fit",
                }),
            });
            if (!response.ok) {
                throw new Error(`Recommendation request failed (${response.status})`);
            }
            const payload = await response.json();
            setRecommendations(payload.recommendations || []);
            setSuccess("Model families ranked successfully.");
        } catch (requestError) {
            setError(requestError instanceof Error ? requestError.message : "Recommendation request failed");
        } finally {
            setBusy(false);
        }
    }

    /**
     * Creates a new annotation task with pre-labeled CV candidates.
     * @returns {Promise<void>} Completion signal.
     */
    async function handleCreateTask() {
        setBusy(true);
        setError("");
        setSuccess("");
        try {
            const candidates = parseArrayJson(candidatesText);
            const response = await fetch(`${API_BASE_URL}/annotations/tasks`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    dataset_name: datasetName,
                    model_name: annotationModelName,
                    candidates,
                }),
            });

            if (!response.ok) {
                throw new Error(`Task creation failed (${response.status})`);
            }

            setSuccess("Annotation task created successfully.");
            await loadAnnotationTasks();
        } catch (requestError) {
            setError(requestError instanceof Error ? requestError.message : "Task creation failed");
        } finally {
            setBusy(false);
        }
    }

    /**
     * Submits one quick correction for the first pending candidate in a task.
     * @param {number} taskId - Annotation task identifier.
     * @param {object} candidate - Candidate object to approve.
     * @returns {Promise<void>} Completion signal.
     */
    async function handleApproveCandidate(taskId, candidate) {
        setBusy(true);
        setError("");
        setSuccess("");

        try {
            const response = await fetch(`${API_BASE_URL}/annotations/tasks/${taskId}/corrections`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    corrections: [
                        {
                            candidate_id: candidate.candidate_id,
                            final_label: candidate.predicted_label,
                            approved: true,
                            notes: "approved from dashboard",
                        },
                    ],
                }),
            });

            if (!response.ok) {
                throw new Error(`Correction submission failed (${response.status})`);
            }

            setSuccess(`Candidate ${candidate.candidate_id} approved.`);
            await loadAnnotationTasks();
        } catch (requestError) {
            setError(requestError instanceof Error ? requestError.message : "Correction submission failed");
        } finally {
            setBusy(false);
        }
    }

    return (
        <main className="app-shell">
            <header className="hero-card">
                <p className="eyebrow">Automated ML Assistant</p>
                <h1>Prediction and Annotation Control Center</h1>
                <p>
                    Diagnose incoming tabular datasets, rank model families with telemetry-aware signals,
                    and run annotation review loops with pre-label correction tracking.
                </p>
            </header>

            <section className="panel-grid">
                <article className="panel">
                    <h2>1. Dataset Diagnostics</h2>
                    <label htmlFor="target-column">Target Column</label>
                    <input
                        id="target-column"
                        value={targetColumn}
                        onChange={(event) => setTargetColumn(event.target.value)}
                    />
                    <label htmlFor="dataset-json">Dataset Rows JSON</label>
                    <textarea
                        id="dataset-json"
                        value={datasetRowsText}
                        onChange={(event) => setDatasetRowsText(event.target.value)}
                        rows={12}
                    />
                    <div className="button-row">
                        <button type="button" onClick={handleRunDiagnostics} disabled={busy}>
                            Run Diagnostics
                        </button>
                    </div>
                    {diagnosticsCards.length > 0 && (
                        <div className="kpi-grid" aria-live="polite">
                            {diagnosticsCards.map((card) => (
                                <div className="kpi" key={card.title}>
                                    <div className="kpi-title">{card.title}</div>
                                    <div className="kpi-value">{card.value}</div>
                                </div>
                            ))}
                        </div>
                    )}
                    {diagnostics?.task_hints?.length > 0 && (
                        <ul className="hint-list">
                            {diagnostics.task_hints.map((hint) => (
                                <li key={hint}>{hint}</li>
                            ))}
                        </ul>
                    )}
                </article>

                <article className="panel">
                    <h2>2. Model Family Recommendations</h2>
                    <label htmlFor="task-type">Task Type</label>
                    <select
                        id="task-type"
                        value={taskType}
                        onChange={(event) => setTaskType(event.target.value)}
                    >
                        <option value="classification">classification</option>
                        <option value="regression">regression</option>
                        <option value="clustering">clustering</option>
                        <option value="time_series">time_series</option>
                        <option value="matrix_factorization">matrix_factorization</option>
                        <option value="anomaly">anomaly</option>
                    </select>
                    <div className="button-row">
                        <button type="button" onClick={handleRecommendModels} disabled={busy || !diagnostics}>
                            Rank Models
                        </button>
                    </div>
                    <div className="recommendation-list" aria-live="polite">
                        {recommendations.length === 0 && (
                            <p className="placeholder">
                                No recommendations yet. Run diagnostics, then request ranking.
                            </p>
                        )}
                        {recommendations.map((item) => (
                            <article className="recommendation" key={item.model_family}>
                                <div className="recommendation-title">{item.model_family}</div>
                                <div className="recommendation-score">Score: {item.score.toFixed(3)}</div>
                                <p>{item.rationale}</p>
                            </article>
                        ))}
                    </div>
                </article>
            </section>

            <section className="panel">
                <h2>3. Annotation Assistant</h2>
                <div className="form-grid">
                    <label htmlFor="dataset-name">Dataset Name</label>
                    <input
                        id="dataset-name"
                        value={datasetName}
                        onChange={(event) => setDatasetName(event.target.value)}
                    />

                    <label htmlFor="annotation-model">Pre-label Model</label>
                    <input
                        id="annotation-model"
                        value={annotationModelName}
                        onChange={(event) => setAnnotationModelName(event.target.value)}
                    />
                </div>
                <label htmlFor="candidates-json">Candidate JSON</label>
                <textarea
                    id="candidates-json"
                    value={candidatesText}
                    onChange={(event) => setCandidatesText(event.target.value)}
                    rows={8}
                />
                <div className="button-row">
                    <button type="button" onClick={handleCreateTask} disabled={busy}>
                        Create Annotation Task
                    </button>
                    <button type="button" onClick={loadAnnotationTasks} disabled={busy}>
                        Refresh Queue
                    </button>
                </div>

                <div className="task-list" aria-live="polite">
                    {annotationTasks.length === 0 && (
                        <p className="placeholder">No annotation tasks yet. Create one to start review.</p>
                    )}
                    {annotationTasks.map((task) => {
                        const pending = getPendingCandidates(task);
                        return (
                            <article className="task-card" key={task.task_id}>
                                <div className="task-head">
                                    <h3>
                                        Task #{task.task_id} · {task.dataset_name}
                                    </h3>
                                    <span className={`status status-${task.status}`}>{task.status}</span>
                                </div>
                                <p>
                                    Model: {task.model_name} · Candidates: {task.candidates.length} · Corrections: {" "}
                                    {task.corrections_count}
                                </p>
                                {pending.length > 0 ? (
                                    <div className="pending-box">
                                        <strong>Next pending:</strong> {pending[0].candidate_id} ({pending[0].predicted_label})
                                        <button
                                            type="button"
                                            onClick={() => handleApproveCandidate(task.task_id, pending[0])}
                                            disabled={busy}
                                        >
                                            Approve Candidate
                                        </button>
                                    </div>
                                ) : (
                                    <p className="placeholder">All candidates reviewed for this task.</p>
                                )}
                            </article>
                        );
                    })}
                </div>
            </section>

            {(error || success) && (
                <section className="flash-wrap" aria-live="polite">
                    {error && <p className="flash flash-error">{error}</p>}
                    {success && <p className="flash flash-success">{success}</p>}
                </section>
            )}
        </main>
    );
}

export default App;
